module jk_flip_flop(
    input rst,
    input reset,
    input j,
    input k,
    output reg q
    );

    always @(posedge rst) begin
        if (reset)
            q <= 1'b0;
        else if (j && ~k)
            q <= 1'b1;
        else if (~j && k)
            q <= 1'b0;
        else if (j && k)
            q <= ~q;
    end
endmodule
